function getCurrentMode(deps: DaemonDeps): ClientMode {
  const stateMode = deps.store.getState()?.mode;
  return stateMode || deps.mode || "apikeys";
}

async function logRoutedRequest(payload: Record<string, unknown>): Promise<void> {
  const requestDir = join(homedir(), ".routstrd", "request");
  const fileName = `${Date.now()}-${randomBytes(8).toString("hex")}.json`;

  await mkdir(requestDir, { recursive: true });
  await writeFile(join(requestDir, fileName), JSON.stringify(payload, null, 2));
}

async function buildStatusOutput(
  deps: DaemonDeps,
): Promise<WalletStatusOutput> {
  const mode = getCurrentMode(deps);

  try {
    const walletState = await deps.walletClient.getStatus();
    if (walletState !== "UNLOCKED") {
      return {
        daemon: "running",
        wallet: "error",
        walletState,
        mode,
        error: getWalletStateMessage(walletState),
      };
    }

    const balances = await deps.walletAdapter.getBalances();
    return {
      daemon: "running",
      wallet: "connected",
      walletState,
      balances,
      mode,
    };
  } catch (error) {
    return {
      daemon: "running",
      wallet: "error",
      walletState: "ERROR",
      mode,
      error: toErrorMessage(error),
    };
  }
}

async function buildWalletDetails(deps: DaemonDeps): Promise<{
  state: CocodState;
  ready: boolean;
  balances?: Record<string, number>;
  unit?: "sat";
  activeMint?: string | null;
}> {
  const state = await deps.walletClient.getStatus();
  if (state !== "UNLOCKED") {
    return { state, ready: false };
  }

  const balances = await deps.walletAdapter.getBalances();
  return {
    state,
    ready: true,
    balances,
    unit: "sat",
    activeMint: deps.walletAdapter.getActiveMintUrl(),
  };
}

